// Product class categories:
// animal - Wildlife and animal artwork
// landscape - Scenic views, nature landscapes, cityscapes
// abstract - Abstract and modern art
// sports - Sports and athletic themes
// character - Cartoon, game, and fictional characters
// nature - Plants, flowers, and natural elements
// fantasy - Magical, celestial, and imaginative themes
// vehicle - Cars, ships, planes, and transportation

// Helper function to search products by keyword
function searchByKeyword(keyword) {
  const lowerKeyword = keyword.toLowerCase();
  return productKeywords.filter(product =>
    product.keywords.some(kw => kw.toLowerCase().includes(lowerKeyword)) ||
    product.name.toLowerCase().includes(lowerKeyword) ||
    product.productClass.toLowerCase().includes(lowerKeyword)
  );
}

// Helper function to get products by class
function getProductsByClass(productClass) {
  return productKeywords.filter(product =>
    product.productClass.toLowerCase() === productClass.toLowerCase()
  );
}

// Helper function to get all available product classes
function getProductClasses() {
  return [...new Set(productKeywords.map(p => p.productClass))];
}

// Export for use in other modules
if (typeof module !== "undefined" && module.exports) {
  module.exports = { productKeywords, searchByKeyword, getProductsByClass, getProductClasses };
}
